// Script: generar_146_chiqui_prevencion.js
// Reorganiza la pantalla Salud/Prevencion con 3 areas y Chiqui en cada una:
//
// Header principal: chiqui_escudo (antes era el logo)
//
// AREA 1 — Signos vitales (chiqui_temperatura)
//   ⚖️ Peso (cerrado por defecto), 🫁 Respiracion, 🌡️ Temperatura
//
// AREA 2 — Prevencion (chiqui_medicamentos)
//   💉 Vacunas, 💊 Antiparasitarios, 🩹 Medicamentos
//
// AREA 3 — Historial medico (chiqui_examen)
//   🏥 Enfermedades, 👁️ Observaciones, 📄 Examenes, 🔍 Revisiones
//
// REPRODUCCION — chiqui_amor (solo hembras no esterilizadas/enteras)
//
// Todo lo anterior intacto: FechaSelector, z-[60], body.overflow,
// modales con Guardar en header, TemperaturaTracker, RespiracionTracker.

const fs = require('fs'); const path = require('path');
function png(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64')); console.log('OK: '+f);
}
function tsx(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8')); console.log('OK: '+f);
}
png('public/chiqui/chiqui_ladeado.png', "");
tsx('app/prevencion/page.tsx', "");
